import{_ as e,o as a,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"冰之讯兮","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/通用魔法/7.无派系或通用/冰之讯兮 .md","filePath":"4.资源分区/4.术法/魔法/通用魔法/7.无派系或通用/冰之讯兮 .md"}'),o={name:"4.资源分区/4.术法/魔法/通用魔法/7.无派系或通用/冰之讯兮 .md"};function p(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"冰之讯兮",tabindex:"-1"},[n("冰之讯兮 "),r("a",{class:"header-anchor",href:"#冰之讯兮","aria-label":'Permalink to "冰之讯兮"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),s('<h1 id="冰之讯兮-1" tabindex="-1">冰之讯兮 <a class="header-anchor" href="#冰之讯兮-1" aria-label="Permalink to &quot;冰之讯兮&quot;">​</a></h1><p>冰之讯兮<br> 某冰系大仙见浮冰在水上漂得贼快，感慨一声“冰之讯兮”，冰跑得真TM快啊，于是创作出以下法术，购买任意法术时，获得相应等级与派系的派系造诣。因为冰系大仙是龙国人，所以以下法术使用的能量为任意东方能量。</p><p>这个冰冰，就是讯啦<br> D+500<br> 类型：攻击技<br> 等级：D<br> 派系：黑暗<br> 花费：2<br> 成分：语言<br> 动作：标准<br> 射程：智力*1<br> 目标：一人<br> 持续：无<br> 进行一次施法攻击，造成寒冰伤害，此次攻击额外具有1高速，1破甲，1威猛，命中后对方会因为你的讥讽在当前场景中只对你发动攻击，直到你倒下，这是一个C级心灵来源的胁迫效果，意志豁免。因为最讯的只有一个，所以你同时只能让一个敌人被你嘲讽。</p><p>冰之讯息<br> D+500<br> 类型：增强技<br> 等级：D<br> 派系：自然<br> 花费：2<br> 成分：语言<br> 动作：移动<br> 射程：无<br> 目标：自身<br> 持续：一场景<br> 听，这是冰的讯息：就是逊啦——就是逊啦——就是逊啦——，真是温暖的话语，浸透了每一个好新人的心身<br> 使用一个移动动作将冰的讯息化为蓝色纹路凝聚在手中的武器或驾驶的载具上，当前场景中使用该武器或载具进行的非施法检定攻击命中时，目标需要进行一次意志豁免，失败则承受心灵来源的持续一场景的C级潮湿效果。</p><p>冰之（鲁）讯——鲁·冰·讯<br> 类型：攻击技<br> 等级：D<br> 派系：物理<br> 花费：2<br> 成分：语言<br> 动作：标准<br> 射程：智力*1<br> 目标：两人<br> 持续：无<br> 门前有两棵树,一棵是枣树,另一棵也是枣树。<br> 这个攻击技可以选择两个目标进行攻击，造成寒冰伤害，且你可以选择其中一个枣树（划掉）目标，令这次攻击对其附带1点不可豁免的冻结点数，另一个目标则附带2点寒冰伤害</p><p>冰之周树人——冰·周<br> 类型：攻击技<br> 等级：D<br> 派系：万变<br> 花费：2<br> 成分：语言<br> 动作：标准<br> 射程：智力*1<br> 目标：一人<br> 持续：无<br> 造成寒冰伤害（万变：精神伤害，看到冰·周受到精神伤害很合理吧），因为‘冰’会萦绕在对方‘周’围，所以附带一点不可豁免冻结点数与一点不可豁免的恶心点数，特殊的，对方可以选择将恶心点数改成亢奋点数。</p><p>冰兮，冰？吸！<br> 类型：攻击技<br> 等级：D<br> 派系：咒击<br> 花费：2<br> 成分：语言<br> 动作：标准<br> 射程：智力*1<br> 目标：一人<br> 持续：无<br> 不知道你在魔法里加了什么，总之中了这招的人很亢奋，获得1点不可豁免的亢奋点数，但同时他也可以清除1点其他的情绪异常点数或剧痛点数，这是1点异常点治疗（医疗池24），魔法里加的那东西说不定可以医用嘛。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=e(o,[["render",p]]);export{f as __pageData,m as default};
